import java.util.*;
public class BoundedWild {
    static <T extends Comparable<T>> void printMin(List<T> list) {
        T min = list.get(0);
        for (T item : list) {
            if (item.compareTo(min) < 0) min = item;
        }
        System.out.println(min);
    }
    public static void main(String[] args) {
        printMin(Arrays.asList(3, 1, 4, 1, 5));
        printMin(Arrays.asList("banana", "apple", "cherry"));
    }
}
